    // ============================================================
    // Comparison Operations
    // ============================================================

    #[test]
    fn test_execute_equality() {
        let mut interp = Interpreter::new();
        let result = interp.execute("5 === 5;").unwrap();
        assert_eq!(result, Value::Boolean(true));

        let result = interp.execute("5 === 6;").unwrap();
        assert_eq!(result, Value::Boolean(false));
    }

    #[test]
    fn test_execute_inequality() {
        let mut interp = Interpreter::new();
        let result = interp.execute("5 !== 6;").unwrap();
        assert_eq!(result, Value::Boolean(true));
    }

    #[test]
    fn test_execute_less_than() {
        let mut interp = Interpreter::new();
        let result = interp.execute("3 < 5;").unwrap();
        assert_eq!(result, Value::Boolean(true));

        let result = interp.execute("5 < 3;").unwrap();
        assert_eq!(result, Value::Boolean(false));
    }

    #[test]
    fn test_execute_greater_than() {
        let mut interp = Interpreter::new();
        let result = interp.execute("5 > 3;").unwrap();
        assert_eq!(result, Value::Boolean(true));
    }

    #[test]
    fn test_execute_less_than_or_equal() {
        let mut interp = Interpreter::new();
        let result = interp.execute("5 <= 5;").unwrap();
        assert_eq!(result, Value::Boolean(true));
    }

    #[test]
    fn test_execute_greater_than_or_equal() {
        let mut interp = Interpreter::new();
        let result = interp.execute("5 >= 5;").unwrap();
        assert_eq!(result, Value::Boolean(true));
    }

    // ============================================================
    // Logical Operations
    // ============================================================

    #[test]
    fn test_execute_logical_and() {
        let mut interp = Interpreter::new();
        let result = interp.execute("true && true;").unwrap();
        assert_eq!(result, Value::Boolean(true));

        let result = interp.execute("true && false;").unwrap();
        assert_eq!(result, Value::Boolean(false));
    }

    #[test]
    fn test_execute_logical_or() {
        let mut interp = Interpreter::new();
        let result = interp.execute("true || false;").unwrap();
        assert_eq!(result, Value::Boolean(true));

        let result = interp.execute("false || false;").unwrap();
        assert_eq!(result, Value::Boolean(false));
    }

    #[test]
    fn test_execute_logical_not() {
        let mut interp = Interpreter::new();
        let result = interp.execute("!true;").unwrap();
        assert_eq!(result, Value::Boolean(false));

        let result = interp.execute("!false;").unwrap();
        assert_eq!(result, Value::Boolean(true));
    }

    // ============================================================
    // Array Operations
    // ============================================================

    #[test]
    fn test_execute_array_literal() {
        let mut interp = Interpreter::new();
        let result = interp.execute("[1, 2, 3];").unwrap();
        match result {
            Value::Array(arr) => {
                assert_eq!(arr.len(), 3);
                assert_eq!(arr[0], Value::Number(1));
                assert_eq!(arr[1], Value::Number(2));
                assert_eq!(arr[2], Value::Number(3));
            }
            _ => panic!("Expected array, got {:?}", result),
        }
    }

    #[test]
    fn test_execute_empty_array() {
        let mut interp = Interpreter::new();
        let result = interp.execute("[];").unwrap();
        match result {
            Value::Array(arr) => {
                assert_eq!(arr.len(), 0);
            }
            _ => panic!("Expected empty array"),
        }
    }

    // ============================================================
    // Object Operations
    // ============================================================

    #[test]
    fn test_execute_object_literal() {
        let mut interp = Interpreter::new();
        let result = interp.execute(r#"{"a": 1, "b": 2};"#).unwrap();
        match result {
            Value::Object(obj) => {
                assert_eq!(obj.get("a"), Some(&Value::Number(1)));
                assert_eq!(obj.get("b"), Some(&Value::Number(2)));
            }
            _ => panic!("Expected object"),
        }
    }

    #[test]
    fn test_execute_empty_object() {
        let mut interp = Interpreter::new();
        let result = interp.execute("{};").unwrap();
        match result {
            Value::Object(obj) => {
                assert_eq!(obj.len(), 0);
            }
            _ => panic!("Expected empty object"),
        }
    }

    // ============================================================
    // Function Declarations and Calls
    // ============================================================

    #[test]
    fn test_execute_simple_function() {
        let mut interp = Interpreter::new();
        let result = interp
            .execute(
                r#"
            function add(a, b) {
                return a + b;
            }
            add(3, 4);
        "#,
            )
            .unwrap();
        assert_eq!(result, Value::Number(7));
    }

    #[test]
    fn test_execute_function_with_return() {
        let mut interp = Interpreter::new();
        let result = interp
            .execute(
                r#"
            function double(x) {
                return x * 2;
            }
            double(21);
        "#,
            )
            .unwrap();
        assert_eq!(result, Value::Number(42));
    }

    #[test]
    fn test_execute_multiple_functions() {
        let mut interp = Interpreter::new();
        let result = interp
            .execute(
                r#"
            function add(a, b) { return a + b; }
            function mul(a, b) { return a * b; }
            mul(add(2, 3), 4);
        "#,
            )
            .unwrap();
        assert_eq!(result, Value::Number(20)); // (2+3) * 4 = 20
    }

    #[test]
    fn test_execute_nested_function_calls() {
        let mut interp = Interpreter::new();
        let result = interp
            .execute(
                r#"
            function f(x) { return x + 1; }
            function g(x) { return x * 2; }
            f(g(f(g(1))));
        "#,
            )
            .unwrap();
        // g(1) = 2, f(2) = 3, g(3) = 6, f(6) = 7
        assert_eq!(result, Value::Number(7));
    }

