    // ============================================================
    // Gas Metering
    // ============================================================

    #[test]
    fn test_gas_exhaustion() {
        let mut interp = Interpreter::new();
        interp.set_gas_limit(10); // Very low limit

        // This should exhaust gas
        let result = interp.execute(
            r#"
            function recursive(n) {
                if (n <= 0) { return 0; }
                else { return recursive(n - 1); }
            }
            recursive(100);
        "#,
        );

        assert!(result.is_err());
    }

    #[test]
    fn test_gas_tracking() {
        let mut interp = Interpreter::new();
        let initial_gas = interp.gas_used();

        let _ = interp.execute("1 + 2 + 3 + 4 + 5;");

        let final_gas = interp.gas_used();
        assert!(final_gas > initial_gas);
    }

    // ============================================================
    // Determinism Tests
    // ============================================================

    #[test]
    fn test_deterministic_execution() {
        let code = r#"
            function compute(x) {
                return x * 2 + 1;
            }
            compute(10) + compute(20);
        "#;

        let mut results = Vec::new();
        for _ in 0..10 {
            let mut interp = Interpreter::new();
            let result = interp.execute(code).unwrap();
            results.push(result);
        }

        // All results should be identical
        for result in &results {
            assert_eq!(result, &results[0]);
        }

        // Verify the value: compute(10) = 21, compute(20) = 41, sum = 62
        assert_eq!(results[0], Value::Number(62));
    }

    #[test]
    fn test_deterministic_json_output() {
        let code = r#"
            const result = {"b": 2, "a": 1};
            JSON.stringifyCanonical(result);
        "#;

        let mut interp = Interpreter::new();
        let result1 = interp.execute(code).unwrap();

        let mut interp2 = Interpreter::new();
        let result2 = interp2.execute(code).unwrap();

        assert_eq!(result1, result2);
    }

    // ============================================================
    // Complex Integration Tests
    // ============================================================

    #[test]
    fn test_simulated_api_handler() {
        let mut interp = Interpreter::new();
        let result = interp
            .execute(
                r#"
            // Simulated generated code from MTPScript compiler
            function compute_result(x, y) {
                return x + y;
            }

            function handle_get__api(input) {
                const result = compute_result(input, 10);
                return JSON.stringifyCanonical({"result": result});
            }

            handle_get__api(5);
        "#,
            )
            .unwrap();

        match result {
            Value::String(s) => {
                assert!(s.contains("result"));
                assert!(s.contains("15")); // 5 + 10 = 15
            }
            _ => panic!("Expected JSON string result"),
        }
    }

    #[test]
    fn test_conditional_logic() {
        let mut interp = Interpreter::new();
        let result = interp
            .execute(
                r#"
            function max(a, b) {
                if (a > b) {
                    return a;
                } else {
                    return b;
                }
            }

            function abs(x) {
                if (x < 0) {
                    return 0 - x;
                } else {
                    return x;
                }
            }

            max(abs(-10), abs(5));
        "#,
            )
            .unwrap();

        assert_eq!(result, Value::Number(10));
    }

    #[test]
    fn test_data_transformation() {
        let mut interp = Interpreter::new();
        let result = interp
            .execute(
                r#"
            const data = {"x": 1, "y": 2, "z": 3};
            const sum = data.x + data.y + data.z;
            {"total": sum, "count": 3};
        "#,
            )
            .unwrap();

        match result {
            Value::Object(obj) => {
                assert_eq!(obj.get("total"), Some(&Value::Number(6)));
                assert_eq!(obj.get("count"), Some(&Value::Number(3)));
            }
            _ => panic!("Expected object result"),
        }
    }

